"use client";

import * as React from "react";
import {
  Container,
  Card,
  CardContent,
  Statistic,
  DataTable,
  type ColumnDef,
  PersonCell,
  Progress,
  Badge,
  Button,
  Select,
  SearchInput,
  Grid,
  HStack,
  VStack,
  Separator,
  EmptyState,
  type SignedRecordValue,
} from "@gunjo/ui";
import {
  IconUserPlus,
  IconChevronRight,
  IconClipboardCheck,
  IconFilterOff,
} from "@tabler/icons-react";
import {
  hires as seedHires,
  type Hire,
  type HireStatus,
  HIRE_STATUS_LABEL,
  taskProgress,
  outstandingDocs,
  overdueTasks,
  summary,
} from "./data";
import { HireStatusBadge, formatDate } from "./shared";
import { HireDetail } from "./HireDetail";

const ALL = "__all__";

export default function EmployeeOnboardingPage() {
  const [hires, setHires] = React.useState<Hire[]>(seedHires);
  const [query, setQuery] = React.useState("");
  const [dept, setDept] = React.useState<string>(ALL);
  const [status, setStatus] = React.useState<string>(ALL);
  const [selectedId, setSelectedId] = React.useState<string | null>(null);
  const [drawerOpen, setDrawerOpen] = React.useState(false);

  // 完了承認レコード（hireId → SignedRecordValue）。初期は確定済データを反映。
  const [records, setRecords] = React.useState<Record<string, SignedRecordValue>>(() =>
    Object.fromEntries(
      seedHires.map((h) => [
        h.id,
        h.finalized
          ? {
              status: "signed" as const,
              signedBy: h.finalizedBy,
              signedAt: h.finalizedAt
                ? new Date(h.finalizedAt).toISOString()
                : new Date().toISOString(),
              addenda: [],
            }
          : { status: "draft" as const, addenda: [] },
      ])
    )
  );

  const departments = React.useMemo(
    () => Array.from(new Set(seedHires.map((h) => h.department))),
    []
  );

  const filtered = React.useMemo(() => {
    const q = query.trim().toLowerCase();
    return hires.filter((h) => {
      const matchesQuery =
        q === "" ||
        h.name.toLowerCase().includes(q) ||
        h.nameKana.toLowerCase().includes(q) ||
        h.role.toLowerCase().includes(q);
      const matchesDept = dept === ALL || h.department === dept;
      const matchesStatus = status === ALL || h.status === status;
      return matchesQuery && matchesDept && matchesStatus;
    });
  }, [hires, query, dept, status]);

  const metrics = React.useMemo(() => summary(hires), [hires]);

  const selected = hires.find((h) => h.id === selectedId) ?? null;

  const openDetail = React.useCallback((hire: Hire) => {
    setSelectedId(hire.id);
    setDrawerOpen(true);
  }, []);

  const toggleTask = React.useCallback(
    (hireId: string, taskId: string, done: boolean) => {
      setHires((prev) =>
        prev.map((h) =>
          h.id === hireId
            ? {
                ...h,
                tasks: h.tasks.map((t) => (t.id === taskId ? { ...t, done } : t)),
              }
            : h
        )
      );
    },
    []
  );

  const updateRecord = React.useCallback(
    (hireId: string, value: SignedRecordValue) => {
      setRecords((prev) => ({ ...prev, [hireId]: value }));
      // 署名されたら本人のステータスを「完了」に同期
      if (value.status === "signed") {
        setHires((prev) =>
          prev.map((h) =>
            h.id === hireId
              ? {
                  ...h,
                  finalized: true,
                  finalizedBy: value.signedBy,
                  finalizedAt: value.signedAt,
                  status: "done",
                }
              : h
          )
        );
      }
    },
    []
  );

  const resetFilters = () => {
    setQuery("");
    setDept(ALL);
    setStatus(ALL);
  };

  const filtersActive = query !== "" || dept !== ALL || status !== ALL;

  const columns: ColumnDef<Hire>[] = [
    {
      id: "person",
      header: "入社者",
      cell: ({ row }) => {
        const h = row.original;
        return (
          <PersonCell
            name={h.name}
            secondary={`${h.department}・${h.role}`}
            tertiary={h.nameKana}
          />
        );
      },
    },
    {
      id: "joinDate",
      header: "入社日",
      cell: ({ row }) => (
        <span className="whitespace-nowrap tabular-nums">{formatDate(row.original.joinDate)}</span>
      ),
    },
    {
      id: "mentor",
      header: "メンター / 担当HR",
      cell: ({ row }) => (
        <div className="flex flex-col text-sm">
          <span>{row.original.mentor}</span>
          <span className="text-xs text-muted-foreground">HR: {row.original.hrOwner}</span>
        </div>
      ),
    },
    {
      id: "progress",
      header: "進捗",
      cell: ({ row }) => {
        const p = taskProgress(row.original);
        return (
          <div className="flex min-w-[120px] flex-col gap-1">
            <div className="flex items-center justify-between text-xs">
              <span className="font-medium tabular-nums">{p.pct}%</span>
              <span className="text-muted-foreground tabular-nums">
                {p.done}/{p.total}
              </span>
            </div>
            <Progress
              value={p.pct}
              label={`${row.original.name} の進捗`}
              valueText={`${p.done}/${p.total} 完了`}
              tone={p.pct === 100 ? "success" : "primary"}
              className="h-2"
            />
          </div>
        );
      },
    },
    {
      id: "status",
      header: "ステータス",
      cell: ({ row }) => {
        const out = outstandingDocs(row.original);
        const over = overdueTasks(row.original).length;
        return (
          <div className="flex flex-wrap items-center gap-1.5">
            <HireStatusBadge status={row.original.status} />
            {out > 0 ? <Badge variant="warning">書類未提出 {out}</Badge> : null}
            {over > 0 ? <Badge variant="destructive">期限超過 {over}</Badge> : null}
          </div>
        );
      },
    },
    {
      id: "chevron",
      header: "",
      cell: () => (
        <IconChevronRight className="h-4 w-4 text-muted-foreground" aria-hidden />
      ),
    },
  ];

  return (
    <Container className="py-6 sm:py-8">
      <VStack gap={6}>
        {/* ヘッダー */}
        <HStack justify="between" align="start" className="flex-wrap gap-3">
          <div className="flex items-start gap-3">
            <span className="mt-0.5 flex h-9 w-9 shrink-0 items-center justify-center rounded-lg bg-primary/10 text-primary">
              <IconClipboardCheck className="h-5 w-5" aria-hidden />
            </span>
            <div>
              <h1 className="text-xl font-bold tracking-tight">入社手続き / オンボーディング管理</h1>
              <p className="text-sm text-muted-foreground">
                新入社員の手続き進捗・書類提出・完了承認を一元管理します。
              </p>
            </div>
          </div>
          <Button variant="primary">
            <IconUserPlus className="h-4 w-4" aria-hidden />
            入社者を追加
          </Button>
        </HStack>

        {/* サマリーメトリクス */}
        <Grid cols={{ base: 2, md: 5 }} gap={3}>
          <Statistic label="今月の入社者" value={metrics.joiningThisMonth} hint="人" />
          <Statistic label="進行中" value={metrics.inProgress} hint="人" />
          <Statistic
            label="手続き完了"
            value={metrics.done}
            hint="人"
            trend="up"
            tone="positive"
          />
          <Statistic
            label="書類未提出"
            value={metrics.docsOutstanding}
            hint="件"
            trend={metrics.docsOutstanding > 0 ? "down" : "flat"}
            tone={metrics.docsOutstanding > 0 ? "negative" : "neutral"}
          />
          <Statistic
            label="期限超過タスク"
            value={metrics.overdue}
            hint="件"
            trend={metrics.overdue > 0 ? "down" : "flat"}
            tone={metrics.overdue > 0 ? "negative" : "neutral"}
          />
        </Grid>

        {/* リスト */}
        <Card>
          <CardContent className="flex flex-col gap-4 pt-6">
            {/* フィルター */}
            <div className="flex flex-col gap-3 sm:flex-row sm:items-end">
              <div className="sm:max-w-xs sm:flex-1">
                <SearchInput
                  value={query}
                  onValueChange={setQuery}
                  placeholder="氏名・職種で検索"
                  aria-label="入社者を検索"
                />
              </div>
              <div className="grid grid-cols-2 gap-3 sm:flex sm:flex-none sm:gap-3">
                <Select
                  label="部署"
                  value={dept}
                  onChange={(e) => setDept(e.target.value)}
                >
                  <option value={ALL}>すべての部署</option>
                  {departments.map((d) => (
                    <option key={d} value={d}>
                      {d}
                    </option>
                  ))}
                </Select>
                <Select
                  label="ステータス"
                  value={status}
                  onChange={(e) => setStatus(e.target.value)}
                >
                  <option value={ALL}>すべて</option>
                  {(Object.keys(HIRE_STATUS_LABEL) as HireStatus[]).map((s) => (
                    <option key={s} value={s}>
                      {HIRE_STATUS_LABEL[s]}
                    </option>
                  ))}
                </Select>
              </div>
              {filtersActive ? (
                <Button variant="ghost" size="sm" onClick={resetFilters} className="sm:mb-0.5">
                  <IconFilterOff className="h-4 w-4" aria-hidden />
                  クリア
                </Button>
              ) : null}
            </div>

            <Separator />

            {filtered.length === 0 ? (
              <EmptyState
                title="該当する入社者がいません"
                description="検索条件やフィルターを変更してください。"
                action={
                  filtersActive ? (
                    <Button variant="outline" size="sm" onClick={resetFilters}>
                      フィルターをクリア
                    </Button>
                  ) : undefined
                }
              />
            ) : (
              <DataTable
                columns={columns}
                data={filtered}
                onRowClick={openDetail}
                pageSize={10}
                renderCard={(h) => {
                  const p = taskProgress(h);
                  const out = outstandingDocs(h);
                  const over = overdueTasks(h).length;
                  return (
                    <VStack gap={3}>
                      <PersonCell
                        name={h.name}
                        secondary={`${h.department}・${h.role}`}
                        tertiary={h.nameKana}
                        trailing={<HireStatusBadge status={h.status} />}
                      />
                      <div className="flex flex-col gap-1">
                        <div className="flex items-center justify-between text-xs">
                          <span className="text-muted-foreground">進捗</span>
                          <span className="font-medium tabular-nums">
                            {p.pct}%（{p.done}/{p.total}）
                          </span>
                        </div>
                        <Progress
                          value={p.pct}
                          label={`${h.name} の進捗`}
                          valueText={`${p.done}/${p.total} 完了`}
                          tone={p.pct === 100 ? "success" : "primary"}
                          className="h-2"
                        />
                      </div>
                      <div className="flex flex-wrap items-center gap-1.5">
                        <Badge variant="outline">入社 {formatDate(h.joinDate)}</Badge>
                        <Badge variant="outline">メンター {h.mentor}</Badge>
                        {out > 0 ? <Badge variant="warning">書類未提出 {out}</Badge> : null}
                        {over > 0 ? <Badge variant="destructive">期限超過 {over}</Badge> : null}
                      </div>
                    </VStack>
                  );
                }}
              />
            )}
          </CardContent>
        </Card>
      </VStack>

      {/* 詳細ドロワー */}
      <HireDetail
        hire={selected}
        open={drawerOpen}
        onOpenChange={setDrawerOpen}
        onToggleTask={toggleTask}
        signedRecord={
          selected
            ? records[selected.id] ?? { status: "draft", addenda: [] }
            : { status: "draft", addenda: [] }
        }
        onSignedRecordChange={updateRecord}
      />
    </Container>
  );
}

// 入社手続き / オンボーディング管理 — ドメインデータ
// 架空の社内 HR チーム向け。氏名・部署・日付は現実的なサンプル。

export type HireStatus = "before" | "day1" | "week1" | "month1" | "done";

export const HIRE_STATUS_LABEL: Record<HireStatus, string> = {
  before: "入社前",
  day1: "初日対応中",
  week1: "1週間フォロー",
  month1: "1ヶ月フォロー",
  done: "手続き完了",
};

export type TaskPhase = "before" | "day1" | "week1" | "month1";

export const PHASE_LABEL: Record<TaskPhase, string> = {
  before: "入社前",
  day1: "初日",
  week1: "1週間以内",
  month1: "1ヶ月以内",
};

export const PHASE_ORDER: TaskPhase[] = ["before", "day1", "week1", "month1"];

export interface OnboardingTask {
  id: string;
  phase: TaskPhase;
  label: string;
  owner: string; // 担当（HR / メンター / 本人）
  due: string; // YYYY-MM-DD
  done: boolean;
}

export type DocStatus = "submitted" | "outstanding" | "review";

export const DOC_STATUS_LABEL: Record<DocStatus, string> = {
  submitted: "提出済",
  review: "確認中",
  outstanding: "未提出",
};

export interface OnboardingDoc {
  id: string;
  name: string;
  status: DocStatus;
  required: boolean;
  receivedAt?: string;
}

export interface Hire {
  id: string;
  name: string;
  nameKana: string;
  joinDate: string; // 入社日
  department: string;
  role: string;
  employmentType: "正社員" | "契約社員" | "中途" | "新卒";
  hrOwner: string; // 担当 HR
  mentor: string; // メンター
  mentorRole: string;
  status: HireStatus;
  finalized: boolean; // HR が手続き完了を確定したか
  finalizedBy?: string;
  finalizedAt?: string; // ISO
  tasks: OnboardingTask[];
  docs: OnboardingDoc[];
}

// ---- 標準タスクテンプレ（フェーズ別） ----
function buildTasks(
  joinDate: string,
  owners: { hr: string; mentor: string; self: string },
  doneFlags: Record<string, boolean>
): OnboardingTask[] {
  const d = (offsetDays: number) => {
    const base = new Date(joinDate + "T00:00:00");
    base.setDate(base.getDate() + offsetDays);
    return base.toISOString().slice(0, 10);
  };
  const t = (
    id: string,
    phase: TaskPhase,
    label: string,
    owner: string,
    offset: number
  ): OnboardingTask => ({
    id,
    phase,
    label,
    owner,
    due: d(offset),
    done: doneFlags[id] ?? false,
  });

  return [
    // 入社前
    t("contract", "before", "雇用契約の締結", owners.hr, -7),
    t("docs-submit", "before", "必要書類の提出依頼・回収", owners.hr, -5),
    t("equipment", "before", "PC・機材の手配", "情シス", -3),
    t("account-prep", "before", "アカウント発行準備", "情シス", -2),
    // 初日
    t("account-issue", "day1", "各種アカウント発行（メール/Slack）", "情シス", 0),
    t("id-card", "day1", "入館証・社員証の発行", owners.hr, 0),
    t("orientation", "day1", "入社オリエンテーション", owners.hr, 0),
    t("welcome", "day1", "チーム顔合わせ・席案内", owners.mentor, 0),
    // 1週間
    t("training", "week1", "セキュリティ研修の受講", owners.self, 5),
    t("mentor-1on1", "week1", "メンター初回 1on1", owners.mentor, 4),
    t("benefit-reg", "week1", "社会保険・福利厚生の登録", owners.hr, 5),
    t("tools-setup", "week1", "開発環境・各種ツール設定", owners.self, 5),
    // 1ヶ月
    t("goal-setting", "month1", "目標設定（試用期間ゴール）", owners.mentor, 25),
    t("follow-1on1", "month1", "1ヶ月フォロー面談（HR）", owners.hr, 28),
    t("survey", "month1", "オンボーディングアンケート回答", owners.self, 30),
  ];
}

const STANDARD_DOCS: { id: string; name: string; required: boolean }[] = [
  { id: "pension", name: "年金手帳（基礎年金番号）", required: true },
  { id: "employment-contract", name: "雇用契約書（本人控）", required: true },
  { id: "emergency", name: "緊急連絡先届", required: true },
  { id: "tax", name: "扶養控除等申告書", required: true },
  { id: "bank", name: "給与振込口座届", required: true },
  { id: "mynumber", name: "マイナンバー提出", required: true },
  { id: "commute", name: "通勤経路届", required: false },
];

function buildDocs(states: Record<string, DocStatus>, receivedBase: string): OnboardingDoc[] {
  return STANDARD_DOCS.map((d, i) => {
    const status = states[d.id] ?? "outstanding";
    return {
      ...d,
      status,
      receivedAt:
        status === "submitted" || status === "review"
          ? offsetDate(receivedBase, -(7 - i))
          : undefined,
    };
  });
}

function offsetDate(iso: string, offsetDays: number): string {
  const base = new Date(iso + "T00:00:00");
  base.setDate(base.getDate() + offsetDays);
  return base.toISOString().slice(0, 10);
}

