// ---- 派生メトリクス ----
export function taskProgress(hire: Hire): { done: number; total: number; pct: number } {
  const total = hire.tasks.length;
  const done = hire.tasks.filter((t) => t.done).length;
  return { done, total, pct: total === 0 ? 0 : Math.round((done / total) * 100) };
}

export function outstandingDocs(hire: Hire): number {
  return hire.docs.filter((d) => d.required && d.status === "outstanding").length;
}

// 今日を基準にした期限超過タスク（未完了 & 期限が過去）
export const TODAY = "2026-06-26";

export function overdueTasks(hire: Hire): OnboardingTask[] {
  return hire.tasks.filter((t) => !t.done && t.due < TODAY);
}

export function summary(list: Hire[]) {
  const joiningThisMonth = list.filter((h) => h.joinDate.slice(0, 7) === TODAY.slice(0, 7)).length;
  const inProgress = list.filter((h) => !h.finalized).length;
  const done = list.filter((h) => h.finalized).length;
  const docsOutstanding = list.reduce((acc, h) => acc + outstandingDocs(h), 0);
  const overdue = list.reduce((acc, h) => acc + overdueTasks(h).length, 0);
  return { joiningThisMonth, inProgress, done, docsOutstanding, overdue };
}

