// タスクの担当ラベル + 期限を CheckList の description / trailing に流し込む
function taskToItem(task: OnboardingTask): CheckListItem {
  const overdue = !task.done && task.due < TODAY;
  return {
    id: task.id,
    label: task.label,
    description: `担当: ${task.owner}`,
    checked: task.done,
    trailing: (
      <span
        className={
          "inline-flex items-center gap-1 text-xs " +
          (overdue ? "font-medium text-destructive" : "text-muted-foreground")
        }
      >
        {overdue ? <IconAlertTriangle className="h-3.5 w-3.5" aria-hidden /> : <IconCalendarDue className="h-3.5 w-3.5" aria-hidden />}
        <span>
          期限 {formatDate(task.due)}
          {overdue ? "（超過）" : ""}
        </span>
      </span>
    ),
  };
}

// フェーズの進捗から承認ルート風タイムラインの状態を導く
function phaseSteps(hire: Hire): ApprovalStep[] {
  return PHASE_ORDER.map((phase) => {
    const tasks = hire.tasks.filter((t) => t.phase === phase);
    const done = tasks.filter((t) => t.done).length;
    const allDone = done === tasks.length;
    const anyDone = done > 0;
    const state: ApprovalStep["state"] = allDone
      ? "approved"
      : anyDone
      ? "current"
      : "pending";
    return {
      label: PHASE_LABEL[phase],
      state,
      actor: `${done}/${tasks.length} 完了`,
    };
  });
}

export function HireDetail({
