        </SheetHeader>

        <div className="flex flex-1 flex-col gap-6 overflow-y-auto px-4 py-4">
          {/* 本人サマリー */}
          <PersonCell
            size="lg"
            name={hire.name}
            secondary={`${hire.department}・${hire.role}`}
            tertiary={`${hire.nameKana} / ${hire.employmentType}`}
            trailing={<HireStatusBadge status={hire.status} />}
          />

          <MetadataList
            layout="horizontal"
