              { label: "入社日", value: formatDate(hire.joinDate) },
              { label: "雇用形態", value: hire.employmentType },
              { label: "担当 HR", value: hire.hrOwner },
            ]}
          />

          {/* メンター（PersonCell の再利用） */}
          <VStack gap={2}>
            <p className="text-xs font-medium text-muted-foreground">メンター</p>
            <PersonCell
              size="sm"
              name={hire.mentor}
              secondary={hire.mentorRole}
            />
          </VStack>

          <Separator />

          {/* 進捗メトリクス */}
          <Grid cols={3} gap={3}>
            <Statistic label="進捗" value={`${progress.pct}%`} hint={`${progress.done}/${progress.total} 完了`} />
            <Statistic
              label="書類未提出"
              value={docsOut}
              trend={docsOut > 0 ? "down" : "flat"}
              tone={docsOut > 0 ? "negative" : "neutral"}
            />
            <Statistic
              label="期限超過"
              value={overdue.length}
              trend={overdue.length > 0 ? "down" : "flat"}
              tone={overdue.length > 0 ? "negative" : "neutral"}
            />
          </Grid>
          <div>
            <Progress
              value={progress.pct}
              label={`${hire.name} のオンボーディング進捗`}
              valueText={`${progress.done}/${progress.total} タスク完了`}
              tone={progress.pct === 100 ? "success" : "primary"}
            />
          </div>

          {/* フェーズ進行（承認ルート風タイムライン） */}
          <VStack gap={2}>
            <p className="text-sm font-semibold">フェーズ進行</p>
            <ApprovalSteps
              steps={phaseSteps(hire)}
              stateLabels={{ approved: "完了", current: "進行中", pending: "未着手" }}
            />
          </VStack>

          <Separator />

          {/* タブ: チェックリスト / 書類 / 完了承認 */}
          <Tabs defaultValue="tasks">
            <TabsList>
              <TabsTrigger value="tasks">タスク</TabsTrigger>
              <TabsTrigger value="docs">書類</TabsTrigger>
              <TabsTrigger value="signoff">完了承認</TabsTrigger>
            </TabsList>

            {/* タスク（フェーズ別チェックリスト） */}
            <TabsContent value="tasks">
              <VStack gap={4}>
                {PHASE_ORDER.map((phase) => {
                  const items = hire.tasks
                    .filter((t) => t.phase === phase)
                    .map(taskToItem);
                  return (
                    <VStack key={phase} gap={2}>
                      <HStack align="center" justify="between">
                        <p className="text-sm font-semibold">{PHASE_LABEL[phase]}</p>
                        <Badge variant="outline">
                          {items.filter((i) => i.checked).length}/{items.length}
                        </Badge>
                      </HStack>
                      <CheckList
                        items={items}
                        onCheckedChange={(taskId, done) =>
                          onToggleTask(hire.id, taskId, done)
                        }
                      />
                    </VStack>
                  );
                })}
              </VStack>
            </TabsContent>

            {/* 書類提出状況 */}
            <TabsContent value="docs">
              <CheckList
                items={hire.docs.map((doc) => ({
                  id: doc.id,
                  label: doc.name,
                  description: doc.required ? "必須" : "任意",
                  trailing: (
