              <SignedRecord
                value={signedRecord}
                onChange={(v) => onSignedRecordChange(hire.id, v)}
                signerId={hire.hrOwner}
                canSign={canFinalize}
                labels={{
                  draft: "未確定",
                  signed: "手続き完了 確定済",
                  sign: "手続き完了を確定する",
                  locked: "確定済のため編集できません（追記のみ可）",
                  addendaTitle: "確定後の追記",
                  addendum: "追記",
                  addendumBody: "追記内容",
                  addendumReason: "理由",
                  addendumSubmit: "追記する",
                  cancel: "キャンセル",
                  signedByLabel: "確定者",
                }}
              >
                {({ readOnly }) => (
                  <div className="flex flex-col gap-3 text-sm">
                    <p className="font-medium">入社手続き完了サマリー</p>
                    {!canFinalize && !readOnly ? (
                      <p className="flex items-start gap-2 rounded-md border border-warning-border bg-warning-subtle px-3 py-2 text-warning-subtle-foreground">
                        <IconAlertTriangle className="mt-0.5 h-4 w-4 shrink-0" aria-hidden />
                        <span>
                          すべてのタスク完了（現在 {progress.pct}%）と必須書類の提出（未提出 {docsOut} 件）が確定の前提条件です。
                        </span>
                      </p>
                    ) : null}
                    {canFinalize ? (
                      <p className="flex items-start gap-2 rounded-md border border-success-border bg-success-subtle px-3 py-2 text-success-subtle-foreground">
                        <IconCheck className="mt-0.5 h-4 w-4 shrink-0" aria-hidden />
                        <span>すべてのタスク・必須書類が揃いました。手続き完了を確定できます。</span>
                      </p>
                    ) : null}
                    <MetadataList
                      items={[
                        { label: "対象者", value: `${hire.name}（${hire.department}）` },
                        { label: "入社日", value: formatDate(hire.joinDate) },
                        { label: "タスク進捗", value: `${progress.done}/${progress.total}（${progress.pct}%）` },
                        { label: "必須書類", value: docsOut === 0 ? "すべて提出済" : `未提出 ${docsOut} 件` },
                        { label: "確定担当 HR", value: hire.hrOwner },
                      ]}
                    />
                  </div>
                )}
              </SignedRecord>
            </TabsContent>
          </Tabs>
        </div>

        <SheetFooter className="border-t px-4 py-4">
          <SheetClose asChild>
            <Button variant="outline">閉じる</Button>
          </SheetClose>
        </SheetFooter>
      </SheetContent>
    </Sheet>
  );
}

