// ステータス → Badge variant（色だけに依存しないようラベルも常に表示）
const HIRE_STATUS_VARIANT: Record<HireStatus, React.ComponentProps<typeof Badge>["variant"]> = {
  before: "outline",
  day1: "info",
  week1: "info",
  month1: "warning",
  done: "success",
};

export function HireStatusBadge({ status }: { status: HireStatus }) {
  return <Badge variant={HIRE_STATUS_VARIANT[status]}>{HIRE_STATUS_LABEL[status]}</Badge>;
}

const DOC_STATUS_VARIANT: Record<DocStatus, React.ComponentProps<typeof Badge>["variant"]> = {
  submitted: "success",
  review: "info",
  outstanding: "warning",
};

export function DocStatusBadge({ status }: { status: DocStatus }) {
  return <Badge variant={DOC_STATUS_VARIANT[status]}>{DOC_STATUS_LABEL[status]}</Badge>;
}

// 入社日などの日付を和暦風ではなく ISO のまま読みやすく
export function formatDate(iso: string): string {
  const m = /^(\d{4})-(\d{2})-(\d{2})/.exec(iso);
  return m ? `${m[1]}/${m[2]}/${m[3]}` : iso;
}
